computed.formula:
/****
 * Build TOTALS array by summing numeric fields from AS_IF and ROWS.
 * Some fields are averaged, and CQP_COMBINED_RADIO is calculated from components.
 * By Adriana Centellas
 ****/

  // Fields that should be summed
  const sumFields = [
    "CQP_CLAIM_USD",
    "CQP_GWP_USD",
    "CQP_FORTE_SHARE",
    "CQP_NWP",
    "CQP_LOSS_RADIO"
  ];

  // Fields that should be averaged
  const avgFields = [
    "CQP_BROKERAGE_COMISSION",
    "CQP_TAX",
    "CQP_UNDERWRITING_EXPENSES"
  ];

  const totals = {
    form_html_viewer: null
  };

  // Init sum fields
  sumFields.forEach(f => totals[f] = 0);

  // Init average fields + counters
  avgFields.forEach(f => {
    totals[f] = 0;
    totals[f + "_COUNT"] = 0;
  });

  function addValue(field, value, isAverage) {
    const num = parseFloat(value);
    if (isNaN(num)) return;

    if (isAverage) {
      totals[field] += num;
      totals[field + "_COUNT"]++;
    } else {
      totals[field] += num;
    }
  }

  // Add values from AS_IF
  this.AS_IF.forEach(row => {
    sumFields.forEach(f => addValue(f, row[f], false));
    avgFields.forEach(f => addValue(f, row[f], true));
  });

  // Add values from ROWS
  this.ROWS.forEach(row => {
    sumFields.forEach(f => addValue(f, row[f], false));
    avgFields.forEach(f => addValue(f, row[f], true));
  });

  // Compute averages
  avgFields.forEach(f => {
    const count = totals[f + "_COUNT"];
    totals[f] = count > 0 ? totals[f] / count : 0;
    delete totals[f + "_COUNT"];
  });

  //  Compute CQP_COMBINED_RADIO based on other fields
  totals.CQP_COMBINED_RADIO =
    (parseFloat(totals.CQP_BROKERAGE_COMISSION) || 0) +
    (parseFloat(totals.CQP_TAX) || 0) +
    (parseFloat(totals.CQP_LOSS_RADIO) || 0) +
    (parseFloat(totals.CQP_UNDERWRITING_EXPENSES) || 0);

  return [totals];

